var e=[{id:`L2_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`여러분. 제가 의식을 치르는 동안 뒤를 부탁드립니다.`,JPN:`皆さま。私が儀式を行っている間、後を頼みます。`,ENG:`Everyone, I ask all of you to protect me while I perform the ritual.`,TWN:`各位，在我進行儀式期間，其他事就要麻煩大家。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`당주님 곁은 제가 엄호하겠습니다.`,JPN:`当主のそばは私が援護いたします。`,ENG:`I will guard Lady Nanahara's side.`,TWN:`我會隨伺在側保護堂主。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`SOLDIER_NPC_NANAHARA_NULL`,text:{KOREA:`침식파 농도 급상승 확인! 사령으로 추정되는 다수의 움직임을 포착했습니다!`,JPN:`侵食波の濃度が急上昇していることを確認！　邪霊と推測される多数の動きをとらえました！`,ENG:`The density of the Corruption ray is increasing rapidly! Also detecting movements of what I presume to be Ghouls!`,TWN:`侵蝕波濃度快速上升中！發現多個疑似邪靈的行跡！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOLDIER_NPC_NANAHARA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`SOLDIER_NPC_NANAHARA_NULL`,text:{KOREA:`눈에 잘 보이지 않는 놈들인데, 괜찮은 걸까요?`,JPN:`目には見えないやつらですが、大丈夫でしょうか？`,ENG:`They are hard to see. Will this be okay?`,TWN:`肉眼是看不見它們的，沒問題嗎？`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOLDIER_NPC_NANAHARA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`DRAGON_NANAHARA_NULL_NULL`,text:{KOREA:`봉인역은 나나하라 영지를 둘러싼 내 현역시절에 만든 방어 시스템이다.`,JPN:`封印域は七原領地を取り囲んでいる、わしの現役時代に作った防御システムじゃ。`,ENG:`The Seal Domain is a defense system made when I served that surrounds the whole territory.`,TWN:`封印域是在我任內打造的防禦系統，它覆蓋整個七原領地。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`DRAGON_NANAHARA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`DRAGON_NANAHARA_NULL_NULL`,text:{KOREA:`비록 결계가 사라졌다곤 하나, 봉인역 자체의 기능에는 이상이 없지.`,JPN:`たとえ結界が消えたとしても、封印域自体の機能に異常はない。`,ENG:`Although the barrier is down, the Domain itself will still function as is.`,TWN:`雖然結界已經瓦解，但封印域本身的功能是正常的。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`DRAGON_NANAHARA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`DRAGON_NANAHARA_NULL_NULL`,text:{KOREA:`사령들이 감지역장을 넘어오는 순간 육안으로도 또렷하게 보일 게다.`,JPN:`邪霊が感知力場を越えてくれば、その時からは肉眼でもはっきりと見えるじゃろう。`,ENG:`The moment the Ghouls come within the detection range, we will be able to see them clearly.`,TWN:`邪靈只要越過感應力場就會立刻現形，用肉眼是看得到的。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`DRAGON_NANAHARA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`SOLDIER_NPC_NANAHARA_NULL`,text:{KOREA:`이 빛은……?`,JPN:`この光は……？`,ENG:`This light…?`,TWN:`這光是……？`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOLDIER_NPC_NANAHARA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SOLDIER_NPC_NANAHARA_NULL`,text:{KOREA:`저기! 놈들의 모습이 드러나기 시작했다! 쏴!`,JPN:`あそこ！　やつらの姿が見え始めているぞ！　撃て！`,ENG:`There! They've started to show themselves! Fire!`,TWN:`那裡！它們現形了！開槍！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOLDIER_NPC_NANAHARA_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};